VALUES
  ('social-worker-moex-02001', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於民國103年公布的身心障礙者權利公約施行法，下列條文內容何者錯誤？', '["本公約所揭示保障身心障礙者人權之規定，具有國內法律之效力", "政府應依公約規定建立身心障礙者權利報告制度，於本法施行後2年提出初次國家報告，之後每4年 提出國家報告", "各級政府機關執行公約保障各項身心障礙者人權規定所需之經費，應優先編列，逐步實施", "各級政府機關應依公約規定之內容，就其所主管之法規及行政措施於本法施行後 2 年優先檢視清單， 有不符公約規定者，應於本法施行後3年完成法規之增修、廢止及行政措施之改進，並於本法施行後 4年內，完成其餘法規之制（訂）定、修正或廢止及行政措施之改進"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02002', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國 104 年公布的「兒童及少年高風險家庭關懷輔導處遇實施計畫」，在權責分工中規定承辦單位接受 社會局（處）轉介個案不得無故拒絕，並應在接案後多少日之內進行訪視評估，且多久之內提出評估報 告？', '["5日內進行訪視評估並於1個月內提出評估報告", "10日內進行訪視評估並於1個月內提出評估報告", "15日內進行訪視評估並於1個月內提出評估報告", "20日內進行訪視評估並於1個月內提出評估報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02003', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會救助法中的生活扶助條文內容，低收入戶成員中有下列情形包括年滿65歲、懷胎滿3個月或領有身 心障礙證明者，主管機關得依其原領取現金給付之金額，增加補助，但最高不得逾百分之多少？', '["20", "30", "40", "50"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02004', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按國民年金法第 5 條內容，被保險人及受益人對保險人所為之核定案件發生爭議事項時，應於收到核定 通知文件之翌日起，多少日內先申請審議，對於審議結果不服時，得依法提起訴願及行政訴訟？', '["30日", "40日", "50日", "60日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02005', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按家庭暴力防治法第13條所示，下列條文內容何者錯誤？', '["聲請保護令之程式或要件有欠缺者，法院應以裁定駁回之", "被害人得於審理時，聲請其親屬或個案輔導之社工人員、心理師陪同被害人在場，並得陳述意見", "法院於審理終結前，得聽取直轄市、縣（市）主管機關或社會福利機構之意見", "保護令事件得進行調解或和解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02006', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依性侵害犯罪防治法第14條規定，法院、檢察署、軍事法院、軍事法院檢察署、司法、軍法警察機關及 醫療機構，應由經專業訓練之專人處理性侵害事件，前項專責人員每年應至少接受多少小時性侵害防治 專業訓練課程？', '["4小時", "6小時", "10小時", "12小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02007', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關性別工作平等法在促進工作平等措施方面，其第15條條文內容，下列何者錯誤？', '["雇主於女性受僱者分娩前後，應使其停止工作，給予產假8星期", "妊娠3個月以上流產者，應使其停止工作，給予產假3星期", "受僱者妊娠期間，雇主應給予產檢假5日", "受僱者於其配偶分娩時，雇主應給予陪產假5日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02008', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按兒童及少年性剝削防制條例第18條，直轄市、縣（市）主管機關至遲應於被害人安置後多少日內向法 院提出審前報告，並聲請法院裁定？', '["15日", "30日", "45日", "60日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02009', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關兩公約，即公民與政治權利國際公約及經濟社會文化權利國際公約的內容敘述，何者錯誤？', '["兩公約是聯合國在1966年頒定", "兩公約與世界人權宣言，合稱國際人權憲章", "我國在2009年通過兩公約施行法，且兩公約所揭示保障人權之規定具有國內法律之效力", "各級政府機關應依兩公約規定之內容，檢討所主管之法令及行政措施，有不符兩公約規定者，應於本 法施行後3年內完成法令之制（訂）定、修正或廢止及行政措施之改進"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02010', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於社會福利公益信託許可及監督辦法，公益信託有下列各款情事，包括違反設立許可條件或監督命令、 為有害公益之行為、無正當理由連續 3 年不為活動。主管應通知委託人、信託監察人及受託人於多少日 內表示意見，屆期不表示或雖表示而無正當理由者，主管機關得依法廢止其許可及其他必要處置？', '["10日", "15日", "20日", "30日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
